// Tolerant UK postcode pattern — matches both spaced and unspaced forms.
// Based on ONS/Royal Mail standard, case-insensitive.
const UK_POSTCODE_REGEX = /^[A-Z]{1,2}\d[A-Z\d]?\s*\d[A-Z]{2}$/i;

/** Normalise UK postcode to uppercase with a single space before the inward code. */
function normalizePostcode(raw: string): string {
  const upper = raw.toUpperCase().replace(/\s+/g, "");
