/**
 * Saved Properties MCP Tools
 *
 * List, save, and react to properties.
 * Schemas imported from @repo/api-contract to match route-level validation.
 */

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import {
  SavePropertyRequestSchema,
  SetReactionRequestSchema,
} from "@repo/api-contract";
import { z } from "zod";
import { listSavedProperties } from "@/modules/discovery/handlers/saved-properties/list";
import { saveProperty } from "@/modules/discovery/handlers/saved-properties/save";
import { setReaction } from "@/modules/discovery/handlers/saved-properties/set-reaction";
import { validateOrError } from "../lib/validate";
import type { AuthenticatedMcpContext } from "../server";

function getAmount(value: unknown): number | null {
  if (typeof value !== "object" || value === null) {
    return null;
  }
  const amount = (value as { amount?: unknown }).amount;
  return typeof amount === "number" && Number.isFinite(amount) ? amount : null;
}

export function registerSavedTools(
  server: McpServer,
  ctx: AuthenticatedMcpContext
): void {
  // ─── List ────────────────────────────────────────────────────────────

  server.registerTool(
    "get_saved_properties",
    {
      title: "Get saved properties",
      description:
        "List your saved properties with reactions (LOVED, MAYBE, PASS). " +
        "Can filter by reaction type.",
      inputSchema: {
        reaction: z
          .enum(["LOVED", "MAYBE", "PASS"])
          .optional()
          .describe("Filter by reaction type"),
        limit: z.number().min(1).max(50).default(20).describe("Max results"),
        offset: z.number().min(0).default(0).describe("Pagination offset"),
      },
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        openWorldHint: false,
        idempotentHint: true,
      },
    },
    async (args) => {
      const result = await listSavedProperties(ctx.user.id, {
        reaction: args.reaction,
        limit: args.limit,
        offset: args.offset,
      });

      if (!result.success) {
        return {
          content: [
            {
              type: "text" as const,
              text: `Failed to load saved properties: ${result.error}`,
            },
          ],
          isError: true,
        };
      }

      const { savedProperties, total, hasMore } = result.data;

      const lines = savedProperties.map((sp: Record<string, unknown>) => {
        const prop =
          typeof sp.property === "object" && sp.property !== null
            ? (sp.property as Record<string, unknown>)
            : undefined;
        const address =
          typeof prop?.address === "string" ? prop.address : "Unknown address";
        const saleAmount = getAmount(prop?.salePrice);
        const monthlyAmount = getAmount(prop?.monthlyRent);
        let priceStr = "POA";
        if (saleAmount !== null) {
          priceStr = `£${saleAmount.toLocaleString("en-GB")}`;
        } else if (monthlyAmount !== null) {
          priceStr = `£${monthlyAmount.toLocaleString("en-GB")}/mo`;
        }
        const reaction = sp.reaction ?? "none";
        const id = sp.id ?? sp.savedPropertyId ?? "";
        return `- ${priceStr} | ${address} | ${reaction} | savedPropertyId: ${id} (${sp.propertyId})`;
      });

      const summary = [
        `You have ${total} saved properties. Showing ${savedProperties.length}:`,
        "",
        ...lines,
        ...(hasMore ? ["\nMore results available (increase offset)."] : []),
      ].join("\n");

      return {
        structuredContent: { savedProperties, total, hasMore },
        content: [{ type: "text" as const, text: summary }],
      };
    }
  );

  // ─── Save ────────────────────────────────────────────────────────────

  server.registerTool(
    "save_property",
    {
      title: "Save a property",
      description:
        "Save a property to your shortlist. Use the propertyId from search results " +
        "(e.g. 'Rightmove:171095228'). The property's current price is snapshot'd for change tracking.",
      inputSchema: {
        propertyId: z
          .string()
          .min(1)
          .describe("Property ID to save, e.g. 'Rightmove:171095228'"),
      },
      annotations: {
        readOnlyHint: false,
        destructiveHint: false,
        openWorldHint: true,
        idempotentHint: true,
      },
    },
    async ({ propertyId }) => {
      // Validate through api-contract schema (same as Hono route)
      const parsed = validateOrError(SavePropertyRequestSchema, {
        propertyId,
        source: "SEARCH",
      });
      if (parsed.error) {
        return parsed.error;
      }

      const result = await saveProperty(ctx.user.id, parsed.data);

      if (!result.success) {
        const msg = result.exists
          ? `Property ${propertyId} is already saved. Use set_reaction to change your reaction.`
          : `Failed to save property: ${result.error}`;
        return {
          content: [{ type: "text" as const, text: msg }],
          isError: !result.exists,
        };
      }

      const sp = result.data.savedProperty as Record<string, unknown>;
      const prop = sp.property as Record<string, unknown> | undefined;
      const address = (prop?.address ?? propertyId) as string;

      return {
        structuredContent: result.data,
        content: [
          {
            type: "text" as const,
            text: `Saved: ${address} (${propertyId}). Use set_reaction to mark it as LOVED, MAYBE, or PASS.`,
          },
        ],
      };
    }
  );

  // ─── Set Reaction ────────────────────────────────────────────────────

  server.registerTool(
    "set_reaction",
    {
      title: "Set reaction on saved property",
      description:
        "Set your reaction (LOVED, MAYBE, or PASS) on a saved property. " +
        "Use the savedPropertyId from get_saved_properties results.",
      inputSchema: {
        savedPropertyId: z
          .string()
          .uuid()
          .describe("Saved property UUID from get_saved_properties"),
        reaction: z.enum(["LOVED", "MAYBE", "PASS"]).describe("Your reaction"),
      },
      annotations: {
        readOnlyHint: false,
        destructiveHint: false,
        openWorldHint: false,
        idempotentHint: true,
      },
    },
    async ({ savedPropertyId, reaction }) => {
      // Validate through api-contract schema
      const parsed = validateOrError(SetReactionRequestSchema, { reaction });
      if (parsed.error) {
        return parsed.error;
      }

      const result = await setReaction(
        ctx.user.id,
        savedPropertyId,
        parsed.data
      );

      if (!result.success) {
        return {
          content: [
            {
              type: "text" as const,
              text: `Failed to set reaction: ${result.error}`,
            },
          ],
          isError: true,
        };
      }

      return {
        structuredContent: result.data,
        content: [
          {
            type: "text" as const,
            text: `Reaction set to ${reaction} on property ${savedPropertyId}.`,
          },
        ],
      };
    }
  );
}

