/**
 * Compare Properties MCP Tool
 *
 * Side-by-side comparison of 2-4 properties with specs, prices, and scores.
 */

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import {
  type ComparePropertiesResponse,
  ComparePropertiesSchema,
} from "@repo/api-contract";
import { log } from "@repo/observability/node";
import { z } from "zod";
import { CompareProperties } from "@/modules/discovery/handlers/compare/compare";
import { validateOrError } from "../lib/validate";
import type { AuthenticatedMcpContext } from "../server";

/**
 * Escape a cell value for markdown tables. Characters like `|` or newlines
 * break GFM table rendering, and upstream property data (addresses, labels)
 * can legitimately contain both.
 */
function escapeMarkdownCell(value: unknown): string {
  if (value == null) {
    return "?";
  }
  return String(value).replaceAll("|", "\\|").replaceAll(/\r?\n/g, " ").trim();
}

export function registerCompareTools(
  server: McpServer,
  ctx: AuthenticatedMcpContext
) {
  server.registerTool(
    "compare_properties",
    {
      title: "Compare properties",
      description:
        "Compare 2 to 4 properties side by side. Returns specs, prices, locations, " +
        "and comparison dimensions. Use property IDs from search results " +
        "(e.g. 'Rightmove:171095228').",
      inputSchema: {
        propertyIds: z
          .array(z.string().min(1))
          .min(2)
          .max(4)
          .describe("2-4 property IDs to compare"),
      },
      annotations: {
        readOnlyHint: true,
        destructiveHint: false,
        openWorldHint: true,
        idempotentHint: true,
      },
    },
    async ({ propertyIds }) => {
      const parsed = validateOrError(ComparePropertiesSchema, { propertyIds });
      if (parsed.error) {
        return parsed.error;
      }

